  1→import { useMemo, useCallback, useSyncExternalStore } from 'react';
  2→import { useSessions } from '@/hooks/useSessions';
  3→import { useProjects } from '@/hooks/useProjects';
  4→import { useInsights } from '@/hooks/useInsights';
  5→import { useFilterParams } from '@/hooks/useFilterParams';
  6→import { ProjectNav } from '@/components/sessions/ProjectNav';
  7→import { SessionListPanel } from '@/components/sessions/SessionListPanel';
  8→import { SessionDetailPanel } from '@/components/sessions/SessionDetailPanel';
  9→import { Button } from '@/components/ui/button';
 10→import {
 11→  Sheet,
 12→  SheetContent,
 13→  SheetDescription,
 14→  SheetHeader,
 15→  SheetTitle,
 16→  SheetTrigger,
 17→} from '@/components/ui/sheet';
 18→import { ArrowLeft, ChevronDown, MousePointerClick } from 'lucide-react';
 19→
 20→const lgQuery = typeof window !== 'undefined' ? window.matchMedia('(min-width: 1024px)') : null;
 21→function subscribeLg(cb: () => void) {
 22→  lgQuery?.addEventListener('change', cb);
 23→  return () => lgQuery?.removeEventListener('change', cb);
 24→}
 25→function getIsLg() {
 26→  return lgQuery?.matches ?? true;
 27→}
 28→
 29→export default function SessionsPage() {
 30→  const [filters, setFilter, setFilters, clearFilters] = useFilterParams({
 31→    q: '',
 32→    project: 'all',
 33→    source: 'all',
 34→    character: 'all',
 35→    status: 'all',
 36→    session: '',
 37→  });
 38→
 39→  const { data: projects = [], isLoading: projectsLoading } = useProjects();
 40→
 41→  const sessionParams = useMemo(() => {
 42→    const params: { projectId?: string; sourceTool?: string; limit?: number } = { limit: 200 };
 43→    if (filters.project !== 'all') params.projectId = filters.project;
 44→    if (filters.source !== 'all') params.sourceTool = filters.source;
 45→    return params;
 46→  }, [filters.project, filters.source]);
 47→
 48→  const { data: sessions = [], isLoading: sessionsLoading } = useSessions(sessionParams);
 49→  const { data: insights = [], isLoading: insightsLoading } = useInsights();
 50→
 51→  const loading = sessionsLoading || projectsLoading || insightsLoading;
 52→
 53→  const handleSelectProject = useCallback(
 54→    (projectId: string) => {
 55→      const currentSessionId = filters.session;
 56→      if (currentSessionId && projectId !== 'all') {
 57→        const currentSession = sessions.find((s) => s.id === currentSessionId);
 58→        if (currentSession && currentSession.project_id !== projectId) {
 59→          setFilters({ project: projectId, session: '' });
 60→          return;
 61→        }
 62→      }
 63→      setFilter('project', projectId);
 64→    },
 65→    [filters.session, sessions, setFilter, setFilters]
 66→  );
 67→
 68→  const handleSelectSession = useCallback(
 69→    (sessionId: string) => {
 70→      setFilter('session', sessionId);
 71→    },
 72→    [setFilter]
 73→  );
 74→
 75→  const handleFilterChange = useCallback(
 76→    (key: 'q' | 'character' | 'status', value: string) => {
 77→      setFilter(key, value);
 78→    },
 79→    [setFilter]
 80→  );
 81→
 82→  const handleClearFilters = useCallback(() => {
 83→    setFilters({ q: '', character: 'all', status: 'all' });
 84→  }, [setFilters]);
 85→
 86→  const selectedProjectName = useMemo(() => {
 87→    if (filters.project === 'all') return 'All Projects';
 88→    return projects.find((p) => p.id === filters.project)?.name ?? 'Project';
 89→  }, [filters.project, projects]);
 90→
 91→  const showProject = filters.project === 'all';
 92→  const isLg = useSyncExternalStore(subscribeLg, getIsLg);
 93→
 94→  return (
 95→    <div className="flex h-[calc(100vh-3.5rem)]">
 96→      {/* Panel A: Project Nav — visible at xl, Sheet at lg, hidden below */}
 97→      <aside className="hidden xl:flex w-[220px] shrink-0 border-r bg-background overflow-y-auto">
 98→        <div className="w-full">
 99→          <ProjectNav
100→            projects={projects}
101→            selectedProject={filters.project}
102→            selectedSource={filters.source}
103→            onSelectProject={handleSelectProject}
104→            onSelectSource={(source) => setFilter('source', source)}
105→          />
106→        </div>
107→      </aside>
108→
109→      {/* Panel B: Session List */}
110→      <div className="w-full lg:w-80 shrink-0 lg:border-r bg-background flex flex-col overflow-hidden">
111→        {/* Project selector for lg (Sheet trigger) and below xl */}
112→        <div className="xl:hidden shrink-0 px-3 pt-3 pb-1">
113→          <Sheet>
114→            <SheetTrigger asChild>
115→              <Button variant="outline" size="sm" className="w-full justify-between text-xs h-8">
116→                <span className="truncate">{selectedProjectName}</span>
117→                <ChevronDown className="h-3 w-3 shrink-0 ml-1" />
118→              </Button>
119→            </SheetTrigger>
120→            <SheetContent side="left" className="w-[260px] p-0">
121→              <SheetHeader className="px-4 py-3 border-b">
122→                <SheetTitle className="text-sm font-semibold">Projects</SheetTitle>
123→                <SheetDescription className="sr-only">Select a project</SheetDescription>
124→              </SheetHeader>
125→              <ProjectNav
126→                projects={projects}
127→                selectedProject={filters.project}
128→                selectedSource={filters.source}
129→                onSelectProject={handleSelectProject}
130→                onSelectSource={(source) => setFilter('source', source)}
131→              />
132→            </SheetContent>
133→          </Sheet>
134→        </div>
135→
136→        <SessionListPanel
137→          sessions={sessions}
138→          insights={insights}
139→          selectedSessionId={filters.session}
140→          showProject={showProject}
141→          filters={{
142→            q: filters.q,
143→            character: filters.character,
144→            status: filters.status,
145→          }}
146→          onFilterChange={handleFilterChange}
147→          onClearFilters={handleClearFilters}
148→          onSelectSession={handleSelectSession}
149→          loading={loading}
150→        />
151→      </div>
152→
153→      {/* Panel C: Session Detail — visible at lg+, Sheet at md, hidden below */}
154→      <div className="hidden lg:flex flex-1 min-w-0 bg-background overflow-hidden">
155→        {filters.session ? (
156→          <div className="flex-1 overflow-y-auto" key={filters.session}>
157→            <SessionDetailPanel sessionId={filters.session} />
158→          </div>
159→        ) : (
160→          <EmptyDetailState />
161→        )}
162→      </div>
163→
164→      {/* Below lg: Session detail as Sheet from right */}
165→      {!isLg && filters.session && (
166→        <Sheet
167→          open={!!filters.session}
168→          onOpenChange={(open) => {
169→            if (!open) setFilter('session', '');
170→          }}
171→        >
172→          <SheetContent side="right" className="w-full sm:w-[85vw] p-0 flex flex-col">
173→            <SheetHeader className="sr-only">
174→              <SheetTitle>Session Detail</SheetTitle>
175→              <SheetDescription>Session detail view</SheetDescription>
176→            </SheetHeader>
177→            <div className="shrink-0 px-3 pt-3">
178→              <Button
179→                variant="ghost"
180→                size="sm"
181→                className="h-7 text-xs gap-1"
182→                onClick={() => setFilter('session', '')}
183→              >
184→                <ArrowLeft className="h-3 w-3" />
185→                Back to list
186→              </Button>
187→            </div>
188→            <div className="flex-1 overflow-y-auto">
189→              <SessionDetailPanel sessionId={filters.session} />
190→            </div>
191→          </SheetContent>
192→        </Sheet>
193→      )}
194→    </div>
195→  );
196→}
197→
198→function EmptyDetailState() {
199→  return (
200→    <div className="flex-1 flex flex-col items-center justify-center text-center px-8">
201→      <MousePointerClick className="h-10 w-10 text-muted-foreground/40 mb-3" />
202→      <p className="text-sm font-medium text-muted-foreground">Select a session to view details</p>
203→      <p className="text-xs text-muted-foreground/60 mt-1">
204→        Choose a session from the list to see its overview, insights, and conversation.
205→      </p>
206→    </div>
207→  );
208→}
