  1→import { useState, useMemo } from 'react';
  2→import { Folder, FolderOpen } from 'lucide-react';
  3→import { Input } from '@/components/ui/input';
  4→import {
  5→  Select,
  6→  SelectContent,
  7→  SelectItem,
  8→  SelectTrigger,
  9→  SelectValue,
 10→} from '@/components/ui/select';
 11→import { Separator } from '@/components/ui/separator';
 12→import { cn } from '@/lib/utils';
 13→import type { Project } from '@/lib/types';
 14→
 15→interface ProjectNavProps {
 16→  projects: Project[];
 17→  selectedProject: string;
 18→  selectedSource: string;
 19→  onSelectProject: (projectId: string) => void;
 20→  onSelectSource: (source: string) => void;
 21→}
 22→
 23→export function ProjectNav({
 24→  projects,
 25→  selectedProject,
 26→  selectedSource,
 27→  onSelectProject,
 28→  onSelectSource,
 29→}: ProjectNavProps) {
 30→  const [search, setSearch] = useState('');
 31→  const showSearch = projects.length > 8;
 32→
 33→  const totalSessions = useMemo(
 34→    () => projects.reduce((sum, p) => sum + p.session_count, 0),
 35→    [projects]
 36→  );
 37→
 38→  const filteredProjects = useMemo(() => {
 39→    if (!search) return projects;
 40→    const q = search.toLowerCase();
 41→    return projects.filter((p) => p.name.toLowerCase().includes(q));
 42→  }, [projects, search]);
 43→
 44→  return (
 45→    <div className="flex flex-col h-full">
 46→      <div className="p-3 space-y-2">
 47→        {showSearch && (
 48→          <Input
 49→            placeholder="Search projects..."
 50→            value={search}
 51→            onChange={(e) => setSearch(e.target.value)}
 52→            className="h-8 text-xs"
 53→          />
 54→        )}
 55→      </div>
 56→
 57→      <div className="flex-1 overflow-y-auto px-1.5">
 58→        {/* All Projects */}
 59→        <button
 60→          onClick={() => onSelectProject('all')}
 61→          aria-current={selectedProject === 'all' ? 'true' : undefined}
 62→          className={cn(
 63→            'w-full flex items-center justify-between gap-2 px-2.5 py-1.5 rounded-md text-sm transition-colors',
 64→            selectedProject === 'all'
 65→              ? 'bg-accent text-accent-foreground font-medium'
 66→              : 'text-foreground hover:bg-accent/50'
 67→          )}
 68→        >
 69→          <span className="truncate">All Projects</span>
 70→          <span className="text-xs text-muted-foreground tabular-nums shrink-0">{totalSessions}</span>
 71→        </button>
 72→
 73→        <Separator className="my-1.5" />
 74→
 75→        {/* Project list */}
 76→        {filteredProjects.map((project) => {
 77→          const isActive = selectedProject === project.id;
 78→          const Icon = isActive ? FolderOpen : Folder;
 79→          return (
 80→            <button
 81→              key={project.id}
 82→              onClick={() => onSelectProject(project.id)}
 83→              aria-current={isActive ? 'true' : undefined}
 84→              className={cn(
 85→                'w-full flex items-center gap-2 px-2.5 py-1.5 rounded-md text-sm transition-colors',
 86→                isActive
 87→                  ? 'bg-accent text-accent-foreground font-medium'
 88→                  : 'text-foreground hover:bg-accent/50'
 89→              )}
 90→            >
 91→              <Icon className="h-3.5 w-3.5 shrink-0 text-muted-foreground" />
 92→              <span className="truncate text-left flex-1">{project.name}</span>
 93→              <span className="text-xs text-muted-foreground tabular-nums shrink-0">
 94→                {project.session_count}
 95→              </span>
 96→            </button>
 97→          );
 98→        })}
 99→      </div>
100→
101→      {/* Source filter at bottom */}
102→      <div className="p-3 border-t">
103→        <Select value={selectedSource} onValueChange={onSelectSource}>
104→          <SelectTrigger className="h-8 text-xs">
105→            <SelectValue placeholder="All Sources" />
106→          </SelectTrigger>
107→          <SelectContent>
108→            <SelectItem value="all">All Sources</SelectItem>
109→            <SelectItem value="claude-code">Claude Code</SelectItem>
110→            <SelectItem value="cursor">Cursor</SelectItem>
111→            <SelectItem value="codex-cli">Codex CLI</SelectItem>
112→            <SelectItem value="copilot-cli">Copilot CLI</SelectItem>
113→            <SelectItem value="copilot">Copilot</SelectItem>
114→          </SelectContent>
115→        </Select>
116→      </div>
117→    </div>
118→  );
119→}
