  1→import { useMemo } from 'react';
  2→import { Input } from '@/components/ui/input';
  3→import { Button } from '@/components/ui/button';
  4→import {
  5→  Select,
  6→  SelectContent,
  7→  SelectItem,
  8→  SelectTrigger,
  9→  SelectValue,
 10→} from '@/components/ui/select';
 11→import { CompactSessionRow } from './CompactSessionRow';
 12→import { getSessionTitle, getDateGroup, sortDateGroups } from '@/lib/utils';
 13→import { parseJsonField } from '@/lib/types';
 14→import type { Session, Insight, InsightMetadata } from '@/lib/types';
 15→import { SearchX, Terminal } from 'lucide-react';
 16→
 17→const SESSION_CHARACTERS = [
 18→  'deep_focus',
 19→  'bug_hunt',
 20→  'feature_build',
 21→  'exploration',
 22→  'refactor',
 23→  'learning',
 24→  'quick_task',
 25→] as const;
 26→
 27→interface SessionListPanelProps {
 28→  sessions: Session[];
 29→  insights: Insight[];
 30→  selectedSessionId: string;
 31→  showProject: boolean;
 32→  filters: {
 33→    q: string;
 34→    character: string;
 35→    status: string;
 36→  };
 37→  onFilterChange: (key: 'q' | 'character' | 'status', value: string) => void;
 38→  onClearFilters: () => void;
 39→  onSelectSession: (sessionId: string) => void;
 40→  loading: boolean;
 41→}
 42→
 43→export function SessionListPanel({
 44→  sessions,
 45→  insights,
 46→  selectedSessionId,
 47→  showProject,
 48→  filters,
 49→  onFilterChange,
 50→  onClearFilters,
 51→  onSelectSession,
 52→  loading,
 53→}: SessionListPanelProps) {
 54→  const analyzedSessionIds = useMemo(
 55→    () => new Set(insights.map((i) => i.session_id)),
 56→    [insights]
 57→  );
 58→
 59→  const insightCountsBySession = useMemo(() => {
 60→    const map = new Map<string, Record<string, number>>();
 61→    for (const insight of insights) {
 62→      const counts = map.get(insight.session_id) || {};
 63→      counts[insight.type] = (counts[insight.type] || 0) + 1;
 64→      map.set(insight.session_id, counts);
 65→    }
 66→    return map;
 67→  }, [insights]);
 68→
 69→  const sessionOutcomes = useMemo(() => {
 70→    const map = new Map<string, string>();
 71→    for (const insight of insights) {
 72→      if (insight.type === 'summary') {
 73→        const metadata = parseJsonField<InsightMetadata>(insight.metadata, {});
 74→        if (metadata.outcome) {
 75→          map.set(insight.session_id, metadata.outcome);
 76→        }
 77→      }
 78→    }
 79→    return map;
 80→  }, [insights]);
 81→
 82→  const filteredSessions = useMemo(() => {
 83→    return sessions.filter((s) => {
 84→      if (filters.character !== 'all' && s.session_character !== filters.character) return false;
 85→      if (filters.status === 'analyzed' && !analyzedSessionIds.has(s.id)) return false;
 86→      if (filters.status === 'unanalyzed' && analyzedSessionIds.has(s.id)) return false;
 87→      if (filters.q) {
 88→        const q = filters.q.toLowerCase();
 89→        const title = getSessionTitle(s).toLowerCase();
 90→        if (!title.includes(q) && !s.project_name.toLowerCase().includes(q)) return false;
 91→      }
 92→      return true;
 93→    });
 94→  }, [sessions, filters.character, filters.status, filters.q, analyzedSessionIds]);
 95→
 96→  const groupedSessions = useMemo(() => {
 97→    const groups = new Map<string, Session[]>();
 98→    for (const s of filteredSessions) {
 99→      const group = getDateGroup(s.started_at);
100→      const arr = groups.get(group) || [];
101→      arr.push(s);
102→      groups.set(group, arr);
103→    }
104→    return sortDateGroups([...groups.entries()]).map(([group, sessions]) => ({
105→      group,
106→      sessions,
107→    }));
108→  }, [filteredSessions]);
109→
110→  const hasClientFilters =
111→    filters.character !== 'all' || filters.status !== 'all' || !!filters.q;
112→
113→  return (
114→    <div className="flex flex-col h-full">
115→      {/* Search + filters */}
116→      <div className="shrink-0 p-3 space-y-2 border-b">
117→        <Input
118→          placeholder="Search sessions..."
119→          value={filters.q}
120→          onChange={(e) => onFilterChange('q', e.target.value)}
121→          className="h-8 text-xs"
122→        />
123→        <div className="flex gap-2">
124→          <Select
125→            value={filters.character}
126→            onValueChange={(v) => onFilterChange('character', v)}
127→          >
128→            <SelectTrigger className="h-7 text-xs flex-1">
129→              <SelectValue placeholder="Type" />
130→            </SelectTrigger>
131→            <SelectContent>
132→              <SelectItem value="all">All Types</SelectItem>
133→              {SESSION_CHARACTERS.map((c) => (
134→                <SelectItem key={c} value={c} className="capitalize text-xs">
135→                  {c.replace(/_/g, ' ')}
136→                </SelectItem>
137→              ))}
138→            </SelectContent>
139→          </Select>
140→          <Select
141→            value={filters.status}
142→            onValueChange={(v) => onFilterChange('status', v)}
143→          >
144→            <SelectTrigger className="h-7 text-xs flex-1">
145→              <SelectValue placeholder="Status" />
146→            </SelectTrigger>
147→            <SelectContent>
148→              <SelectItem value="all">All Status</SelectItem>
149→              <SelectItem value="analyzed">Analyzed</SelectItem>
150→              <SelectItem value="unanalyzed">Not Analyzed</SelectItem>
151→            </SelectContent>
152→          </Select>
153→        </div>
154→      </div>
155→
156→      {/* Session list */}
157→      <div className="flex-1 overflow-y-auto">
158→        {loading ? (
159→          <div className="p-3 space-y-2">
160→            {Array.from({ length: 5 }).map((_, i) => (
161→              <div key={i} className="animate-pulse space-y-1.5 px-3 py-2.5">
162→                <div className="h-4 bg-muted rounded w-4/5" />
163→                <div className="h-3 bg-muted rounded w-2/5" />
164→                <div className="h-3 bg-muted rounded w-3/5" />
165→              </div>
166→            ))}
167→          </div>
168→        ) : filteredSessions.length === 0 ? (
169→          hasClientFilters ? (
170→            <div className="flex flex-col items-center justify-center py-12 text-center px-4 space-y-2">
171→              <SearchX className="h-6 w-6 text-muted-foreground" />
172→              <p className="text-sm font-medium">No matching sessions</p>
173→              <Button variant="outline" size="sm" onClick={onClearFilters}>
174→                Clear filters
175→              </Button>
176→            </div>
177→          ) : (
178→            <div className="flex flex-col items-center justify-center py-12 text-center px-4 space-y-2">
179→              <Terminal className="h-6 w-6 text-muted-foreground" />
180→              <p className="text-sm font-medium">No sessions yet</p>
181→              <p className="text-xs text-muted-foreground">
182→                Run code-insights sync to get started.
183→              </p>
184→            </div>
185→          )
186→        ) : (
187→          <div>
188→            {groupedSessions.map(({ group, sessions: groupSessions }) => (
189→              <div key={group}>
190→                <div className="px-3 pt-3 pb-1">
191→                  <h3 className="text-[10px] font-semibold uppercase tracking-wider text-muted-foreground">
192→                    {group}
193→                  </h3>
194→                </div>
195→                {groupSessions.map((session) => (
196→                  <CompactSessionRow
197→                    key={session.id}
198→                    session={session}
199→                    isActive={session.id === selectedSessionId}
200→                    showProject={showProject}
201→                    insightCounts={insightCountsBySession.get(session.id)}
202→                    outcome={sessionOutcomes.get(session.id)}
203→                    onClick={() => onSelectSession(session.id)}
204→                  />
205→                ))}
206→              </div>
207→            ))}
208→          </div>
209→        )}
210→      </div>
211→    </div>
212→  );
213→}
214→

  1→import { Badge } from '@/components/ui/badge';
  2→import { Tooltip, TooltipContent, TooltipTrigger } from '@/components/ui/tooltip';
  3→import { SESSION_CHARACTER_COLORS, OUTCOME_DOT } from '@/lib/constants/colors';
  4→import { formatDuration, getSessionTitle, cn } from '@/lib/utils';
  5→import { Sparkles } from 'lucide-react';
  6→import type { Session } from '@/lib/types';
  7→
  8→const SOURCE_LABELS: Record<string, string> = {
  9→  'claude-code': 'Claude Code',
 10→  cursor: 'Cursor',
 11→  'codex-cli': 'Codex CLI',
 12→  'copilot-cli': 'Copilot CLI',
 13→  copilot: 'Copilot',
 14→};
 15→
 16→interface CompactSessionRowProps {
 17→  session: Session;
 18→  isActive: boolean;
 19→  showProject: boolean;
 20→  insightCounts?: Record<string, number>;
 21→  outcome?: string;
 22→  onClick: () => void;
 23→}
 24→
 25→export function CompactSessionRow({
 26→  session,
 27→  isActive,
 28→  showProject,
 29→  insightCounts,
 30→  outcome,
 31→  onClick,
 32→}: CompactSessionRowProps) {
 33→  const startedAt = new Date(session.started_at);
 34→  const endedAt = new Date(session.ended_at);
 35→  const title = getSessionTitle(session);
 36→  const characterColor = session.session_character
 37→    ? (SESSION_CHARACTER_COLORS[session.session_character] ?? 'bg-muted text-muted-foreground')
 38→    : null;
 39→
 40→  const sourceLabel = session.source_tool
 41→    ? (SOURCE_LABELS[session.source_tool] ?? session.source_tool)
 42→    : null;
 43→
 44→  const insightTotal = insightCounts
 45→    ? Object.entries(insightCounts)
 46→        .filter(([type]) => type !== 'summary')
 47→        .reduce((sum, [, n]) => sum + n, 0)
 48→    : 0;
 49→
 50→  return (
 51→    <button
 52→      onClick={onClick}
 53→      aria-current={isActive ? 'true' : undefined}
 54→      className={cn(
 55→        'w-full text-left px-3 py-2.5 transition-colors border-l-2',
 56→        isActive
 57→          ? 'bg-accent/60 border-primary'
 58→          : 'border-transparent hover:bg-accent/40'
 59→      )}
 60→    >
 61→      {/* Title */}
 62→      <p className="text-sm font-medium line-clamp-2 leading-snug">{title}</p>
 63→
 64→      {/* Badges */}
 65→      <div className="flex items-center gap-1.5 mt-1 flex-wrap">
 66→        {outcome && OUTCOME_DOT[outcome] && (
 67→          <Tooltip>
 68→            <TooltipTrigger asChild>
 69→              <span className={cn('w-2 h-2 rounded-full shrink-0', OUTCOME_DOT[outcome].color)} />
 70→            </TooltipTrigger>
 71→            <TooltipContent side="right" className="text-xs">{OUTCOME_DOT[outcome].label}</TooltipContent>
 72→          </Tooltip>
 73→        )}
 74→        {session.session_character && characterColor && (
 75→          <Badge variant="outline" className={`text-[10px] px-1.5 py-0 capitalize ${characterColor}`}>
