 9→import AnalyticsPage from '@/pages/AnalyticsPage';
10→import SettingsPage from '@/pages/SettingsPage';
11→import ExportPage from '@/pages/ExportPage';
12→import JournalPage from '@/pages/JournalPage';
13→
14→const ROUTE_TITLES: Record<string, string> = {
15→  '/dashboard': 'Dashboard',
16→  '/sessions': 'Sessions',
17→  '/insights': 'Insights',
18→  '/analytics': 'Analytics',
19→  '/export': 'Export',
20→  '/journal': 'Journal',
21→  '/settings': 'Settings',
22→};
23→
24→function RouteEffects() {
25→  const { pathname } = useLocation();
26→  const [searchParams] = useSearchParams();
27→  const insightParam = searchParams.get('insight');
28→  const navStartRef = useRef<number>(Date.now());
29→
30→  // Scroll to top on route change, unless deep-linking to a specific insight
31→  useEffect(() => {
32→    const isInsightDeepLink = pathname === '/insights' && insightParam;
33→    if (!isInsightDeepLink) {
34→      window.scrollTo(0, 0);
35→    }
36→  }, [pathname, insightParam]);
37→
38→  // Update document.title per route, track page views, and capture dashboard_loaded
39→  useEffect(() => {
40→    const segment = '/' + pathname.split('/')[1];
41→    const page = ROUTE_TITLES[segment];
42→    document.title = page ? `${page} — Code Insights` : 'Code Insights';
43→
44→    // Track page view on every route change
45→    capturePageView(pathname);
46→
47→    // Capture dashboard_loaded with time since navigation started
48→    if (page) {
49→      const loadTimeMs = Date.now() - navStartRef.current;
50→      captureDashboardLoaded(page.toLowerCase(), loadTimeMs);
51→    }
52→    // Reset nav start for next navigation
53→    navStartRef.current = Date.now();
54→  }, [pathname]);
55→
56→  return null;
57→}
58→
59→export default function App() {
60→  return (
61→    <BrowserRouter>
62→      <RouteEffects />
63→      <Routes>
64→        <Route element={<Layout />}>
65→          <Route index element={<Navigate to="/dashboard" replace />} />
66→          <Route path="/dashboard" element={<DashboardPage />} />
67→          <Route path="/sessions" element={<SessionsPage />} />
68→          <Route path="/sessions/:id" element={<SessionDetailPage />} />
69→          <Route path="/insights" element={<InsightsPage />} />
70→          <Route path="/analytics" element={<AnalyticsPage />} />
71→          <Route path="/settings" element={<SettingsPage />} />
72→          <Route path="/export" element={<ExportPage />} />
73→          <Route path="/journal" element={<JournalPage />} />
74→          <Route path="*" element={<Navigate to="/dashboard" replace />} />
75→        </Route>
76→      </Routes>
77→    </BrowserRouter>
78→  );
79→}
