 1→import { useCallback } from 'react';
 2→import { useSearchParams } from 'react-router';
 3→
 4→type FilterConfig = Record<string, string>;
 5→
 6→export function useFilterParams<T extends FilterConfig>(defaults: T) {
 7→  const [searchParams, setSearchParams] = useSearchParams();
 8→
 9→  const filters = {} as T;
10→  for (const key in defaults) {
11→    (filters as FilterConfig)[key] = searchParams.get(key) || defaults[key];
12→  }
13→
14→  const setFilter = useCallback(
15→    (key: keyof T & string, value: string) => {
16→      setSearchParams(
17→        (prev) => {
18→          const next = new URLSearchParams(prev);
19→          if (value === defaults[key]) {
20→            next.delete(key);
21→          } else {
22→            next.set(key, value);
23→          }
24→          return next;
25→        },
26→        { replace: key === 'q' }
27→      );
28→    },
29→    [setSearchParams, defaults]
30→  );
31→
32→  const setFilters = useCallback(
33→    (updates: Partial<T>) => {
34→      setSearchParams(
35→        (prev) => {
36→          const next = new URLSearchParams(prev);
37→          for (const [key, value] of Object.entries(updates)) {
38→            if (value === defaults[key as keyof T]) {
39→              next.delete(key);
40→            } else {
41→              next.set(key, value as string);
42→            }
43→          }
44→          return next;
45→        },
46→        { replace: false }
47→      );
48→    },
49→    [setSearchParams, defaults]
50→  );
51→
52→  const clearFilters = useCallback(() => {
53→    setSearchParams(
54→      (prev) => {
55→        const next = new URLSearchParams(prev);
56→        for (const key in defaults) {
57→          next.delete(key);
58→        }
59→        return next;
60→      },
61→      { replace: true }
62→    );
63→  }, [setSearchParams, defaults]);
64→
65→  return [filters, setFilter, setFilters, clearFilters] as const;
66→}
