 51→/** Per-item collapsible for learnings and decisions. Shows a 1-2 line preview
 52→ *  with an expand toggle to reveal full structured metadata. */
 53→function CollapsibleInsightItem({ insight }: { insight: Insight }) {
 54→  const [expanded, setExpanded] = useState(false);
 55→  const metadata = parseJsonField<InsightMetadata>(insight.metadata, {});
 56→
 57→  // Build the preview text: use title if available, otherwise first ~120 chars of content
 58→  const previewText = insight.title || insight.content.slice(0, 120);
 59→
 60→  // Hint labels for the expandable sections
 61→  const hintLabel =
 62→    insight.type === 'decision'
 63→      ? 'Situation, Choice, Rationale...'
 64→      : 'What, Why, Takeaway...';
 65→
 66→  // Check if there is structured metadata worth expanding
 67→  const hasStructured =
 68→    insight.type === 'decision'
 69→      ? !!(metadata.situation || metadata.choice || metadata.reasoning)
 70→      : !!(metadata.symptom || metadata.root_cause || metadata.takeaway);
 71→
 72→  return (
 73→    <div className="rounded-md border px-3 py-2.5">
 74→      <button
 75→        className="flex items-start gap-2 w-full text-left group"
 76→        onClick={() => hasStructured && setExpanded(!expanded)}
 77→        aria-expanded={expanded}
 78→        disabled={!hasStructured}
 79→      >
 80→        {hasStructured ? (
 81→          expanded ? (
 82→            <ChevronDown className="h-4 w-4 mt-0.5 shrink-0 text-muted-foreground" />
 83→          ) : (
 84→            <ChevronRight className="h-4 w-4 mt-0.5 shrink-0 text-muted-foreground" />
 85→          )
 86→        ) : (
 87→          <span className="w-4 shrink-0" />
 88→        )}
 89→        <div className="flex-1 min-w-0">
 90→          <p className="text-sm font-medium line-clamp-2">{previewText}</p>
 91→          {!expanded && hasStructured && (
 92→            <p className="text-xs text-muted-foreground/60 mt-0.5">{hintLabel}</p>
 93→          )}
 94→        </div>
 95→      </button>
 96→      {expanded && (
 97→        <div className="ml-6 mt-2 pt-2 border-t">
 98→          {insight.type === 'decision' ? (
 99→            <DecisionContent metadata={metadata} />
100→          ) : (
101→            <LearningContent metadata={metadata} />
102→          )}
103→        </div>
104→      )}
105→    </div>
106→  );
107→}
