138→                  )}
139→                  {pattern.fix && (
140→                    <p className="text-xs text-green-600 mt-1">Fix: {pattern.fix}</p>
141→                  )}
142→                </div>
143→              ))}
144→            </div>
145→          </div>
146→        )}
147→
148→        {sessionTraits.length > 0 && (
149→          <div className="space-y-2">
150→            <div className="flex items-center gap-1.5 text-sm font-medium">
151→              <Compass className="h-3.5 w-3.5 text-blue-500" />
