 57→  );
 58→
 59→  const insightCountsBySession = useMemo(() => {
 60→    const map = new Map<string, Record<string, number>>();
 61→    for (const insight of insights) {
 62→      const counts = map.get(insight.session_id) || {};
 63→      counts[insight.type] = (counts[insight.type] || 0) + 1;
 64→      map.set(insight.session_id, counts);
 65→    }
 66→    return map;
 67→  }, [insights]);
