 3→interface ProgressRingProps {
 4→  value: number;
 5→  max?: number;
 6→  size?: number;
 7→  strokeWidth?: number;
 8→  className?: string;
 9→}
10→
11→function getStrokeColor(score: number): string {
12→  if (score >= 80) return 'stroke-green-500';
13→  if (score >= 60) return 'stroke-yellow-500';
14→  if (score >= 40) return 'stroke-orange-500';
15→  return 'stroke-red-500';
16→}
17→
18→function getTextColor(score: number): string {
19→  if (score >= 80) return 'fill-green-500';
20→  if (score >= 60) return 'fill-yellow-500';
21→  if (score >= 40) return 'fill-orange-500';
22→  return 'fill-red-500';
23→}
24→
25→export function ProgressRing({
26→  value,
27→  max = 100,
28→  size = 64,
29→  strokeWidth = 5,
30→  className,
31→}: ProgressRingProps) {
32→  const radius = (size - strokeWidth) / 2;
33→  const circumference = 2 * Math.PI * radius;
34→  const progress = Math.min(Math.max(value / max, 0), 1);
35→  const offset = circumference * (1 - progress);
36→  const center = size / 2;
37→
38→  return (
39→    <svg
40→      width={size}
41→      height={size}
42→      viewBox={`0 0 ${size} ${size}`}
43→      role="img"
44→      aria-label={`Score: ${value} out of ${max}`}
45→      className={cn('shrink-0', className)}
46→    >
47→      <circle
48→        cx={center}
49→        cy={center}
50→        r={radius}
51→        fill="none"
52→        strokeWidth={strokeWidth}
53→        className="stroke-muted"
54→      />
55→      <circle
56→        cx={center}
57→        cy={center}
58→        r={radius}
59→        fill="none"
60→        strokeWidth={strokeWidth}
61→        strokeDasharray={circumference}
62→        strokeDashoffset={offset}
63→        strokeLinecap="round"
64→        transform={`rotate(-90 ${center} ${center})`}
65→        className={cn('transition-all duration-500', getStrokeColor(value))}
66→      />
67→      <text
68→        x={center}
69→        y={center}
70→        textAnchor="middle"
71→        dominantBaseline="central"
72→        className={cn('text-lg font-bold', getTextColor(value))}
73→        style={{ fontSize: size * 0.3 }}
74→      >
75→        {value}
76→      </text>
77→    </svg>
78→  );
79→}
