 45→/**
 46→ * Format a date range for display.
 47→ * Same day: "Feb 12, 1:20 PM – 3:40 PM"
 48→ * Multi-day: "Feb 12, 1:20 PM – Feb 13, 3:40 PM"
 49→ */
 50→export function formatDateRange(startedAt: Date, endedAt: Date): string {
 51→  const sameDay = startedAt.toDateString() === endedAt.toDateString();
 52→  if (sameDay) {
 53→    return `${format(startedAt, 'MMM d, h:mm a')} – ${format(endedAt, 'h:mm a')}`;
 54→  }
 55→  return `${format(startedAt, 'MMM d, h:mm a')} – ${format(endedAt, 'MMM d, h:mm a')}`;
 56→}
 57→
 58→/**
 59→ * Format a token count with human-friendly units.
 60→ * Examples: "1,234", "45.2K", "3.1M", "6.2B"
 61→ */
 62→export function formatTokenCount(tokens: number): string {
 63→  if (tokens >= 1_000_000_000) return `${(tokens / 1_000_000_000).toFixed(1)}B`;
 64→  if (tokens >= 1_000_000) return `${(tokens / 1_000_000).toFixed(1)}M`;
 65→  if (tokens >= 1_000) return `${(tokens / 1_000).toFixed(1)}K`;
 66→  return tokens.toLocaleString();
 67→}
