 76→export function getDateGroup(dateStr: string): string {
 77→  const date = new Date(dateStr);
 78→  const now = new Date();
 79→  const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
 80→  const yesterday = new Date(today);
 81→  yesterday.setDate(yesterday.getDate() - 1);
 82→
 83→  const sessionDay = new Date(date.getFullYear(), date.getMonth(), date.getDate());
 84→
 85→  if (sessionDay.getTime() === today.getTime()) return 'Today';
 86→  if (sessionDay.getTime() === yesterday.getTime()) return 'Yesterday';
 87→  if (date.getFullYear() !== now.getFullYear()) {
 88→    return format(date, 'EEEE, MMM d, yyyy');
 89→  }
 90→  return format(date, 'EEEE, MMM d');
 91→}
 92→
 93→/**
 94→ * Sort date group entries: Today first, Yesterday second, then remaining groups
 95→ * sorted newest-first by parsing the date label.
 96→ */
 97→export function sortDateGroups<T>(entries: [string, T][]): [string, T][] {
 98→  const now = new Date();
 99→  return [...entries].sort((a, b) => {
100→    const labelA = a[0];
101→    const labelB = b[0];
102→
103→    // Today always first
104→    if (labelA === 'Today') return -1;
105→    if (labelB === 'Today') return 1;
106→    // Yesterday always second
107→    if (labelA === 'Yesterday') return -1;
108→    if (labelB === 'Yesterday') return 1;
109→
110→    // Parse dates from labels for remaining groups (newest first)
111→    const dateA = parseDateGroupLabel(labelA, now);
112→    const dateB = parseDateGroupLabel(labelB, now);
113→    return dateB.getTime() - dateA.getTime();
114→  });
115→}
116→
117→function parseDateGroupLabel(label: string, now: Date): Date {
118→  // Remove the day-of-week prefix (e.g., "Monday, ")
119→  const commaIdx = label.indexOf(', ');
120→  if (commaIdx === -1) return new Date(0);
121→  const datePart = label.slice(commaIdx + 2);
122→  // Try "MMM d, yyyy" first (cross-year labels)
123→  const withYear = parse(datePart, 'MMM d, yyyy', now);
124→  if (!isNaN(withYear.getTime())) return withYear;
125→  // Fall back to "MMM d" (current year)
126→  const currentYear = parse(datePart, 'MMM d', now);
127→  if (!isNaN(currentYear.getTime())) return currentYear;
128→  return new Date(0);
129→}
