 25→export function AnalyzeButton({ session, hasExistingInsights, insightCount }: AnalyzeButtonProps) {
 26→  const [confirmOpen, setConfirmOpen] = useState(false);
 27→  const { state: analysisState, startAnalysis, cancelAnalysis } = useAnalysis();
 28→  const { data: llmConfig } = useLlmConfig();
 29→
 30→  const configured = !!(llmConfig?.provider && llmConfig?.model);
 31→
 32→  const isAnalyzingThisSession =
 33→    analysisState.status === 'analyzing' && analysisState.sessionId === session.id && analysisState.type === 'session';
 34→  const isAnalyzingOther =
 35→    analysisState.status === 'analyzing' && !isAnalyzingThisSession;
 36→  const isCompleteForThisSession =
 37→    (analysisState.status === 'complete' || analysisState.status === 'error') &&
 38→    analysisState.sessionId === session.id &&
 39→    analysisState.type === 'session';
 40→
 41→  const handleAnalyze = () => {
 42→    startAnalysis(session, 'session');
 43→  };
 44→
 45→  const handleClick = () => {
 46→    if (hasExistingInsights && !isCompleteForThisSession) {
 47→      setConfirmOpen(true);
 48→    } else {
 49→      handleAnalyze();
 50→    }
 51→  };
 52→
 53→  const isReanalyze = hasExistingInsights || isCompleteForThisSession;
 54→
 55→  if (!configured) {
 56→    return (
 57→      <div className="flex items-center gap-2 text-sm text-muted-foreground">
 58→        <AlertCircle className="h-4 w-4" />
 59→        <span>
 60→          Configure an AI provider in{' '}
 61→          <Link to="/settings" className="underline hover:text-foreground">
 62→            Settings
 63→          </Link>{' '}
 64→          to analyze sessions
 65→        </span>
 66→      </div>
 67→    );
 68→  }
 69→
 70→  if (isAnalyzingThisSession) {
 71→    return (
 72→      <div className="space-y-3">
 73→        <div className="flex items-center gap-3">
 74→          <Button disabled variant="outline" className="gap-2">
 75→            <Loader2 className="h-4 w-4 animate-spin" />
 76→            {analysisState.progress?.message || `Analyzing "${analysisState.sessionTitle}"...`}
 77→          </Button>
 78→          <Button
 79→            variant="ghost"
 80→            size="sm"
 81→            className="gap-1.5 text-muted-foreground hover:text-foreground"
 82→            onClick={cancelAnalysis}
 83→          >
 84→            <X className="h-3.5 w-3.5" />
 85→            Cancel
 86→          </Button>
 87→        </div>
 88→      </div>
 89→    );
 90→  }
 91→
 92→  if (isAnalyzingOther) {
 93→    return (
 94→      <div className="space-y-3">
 95→        <div className="flex items-center gap-3">
 96→          <Button disabled variant="outline" className="gap-2">
 97→            <Loader2 className="h-4 w-4 animate-spin" />
 98→            Analysis in progress...
 99→          </Button>
100→        </div>
101→        <p className="text-xs text-muted-foreground">
102→          Waiting for &quot;{analysisState.sessionTitle}&quot; to finish
103→        </p>
104→      </div>
105→    );
106→  }
107→
108→  return (
109→    <div className="space-y-3">
110→      <div className="flex items-center gap-3">
111→        <Button
112→          onClick={handleClick}
113→          variant={isReanalyze ? 'outline' : 'default'}
114→          className="gap-2"
115→        >
116→          {isReanalyze ? (
117→            <>
118→              <CheckCircle className="h-4 w-4 text-green-500" />
119→              Re-analyze Session
120→            </>
121→          ) : (
122→            <>
123→              <Sparkles className="h-4 w-4" />
124→              Analyze Session
125→            </>
126→          )}
127→        </Button>
128→
129→        {!isReanalyze && (
130→          <span className="text-xs text-muted-foreground">
131→            {session.message_count} messages
