138→          Replaces existing insights. Uses LLM tokens.
139→        </p>
140→      )}
141→
142→      {isCompleteForThisSession && analysisState.result?.success && (
143→        <div className="text-sm text-green-600">
144→          {analysisState.result.insightCount != null
145→            ? `Analysis complete! ${analysisState.result.insightCount} insight${analysisState.result.insightCount !== 1 ? 's' : ''} saved.`
146→            : 'Analysis complete! Insights saved.'}
147→        </div>
148→      )}
149→
150→      {isCompleteForThisSession && !analysisState.result?.success && (
151→        <div className="flex items-start gap-2 text-sm text-red-500">
152→          <AlertCircle className="h-4 w-4 mt-0.5 shrink-0" />
153→          <span>{analysisState.result?.error || 'Analysis failed'}</span>
154→        </div>
155→      )}
156→
157→      <AlertDialog open={confirmOpen} onOpenChange={setConfirmOpen}>
158→        <AlertDialogContent>
159→          <AlertDialogHeader>
160→            <AlertDialogTitle>Re-analyze this session?</AlertDialogTitle>
161→            <AlertDialogDescription>
162→              This will replace {insightCount ?? 0} existing insight{(insightCount ?? 0) !== 1 ? 's' : ''} with new ones.
163→              This uses LLM tokens and cannot be undone.
164→            </AlertDialogDescription>
165→          </AlertDialogHeader>
166→          <AlertDialogFooter>
167→            <AlertDialogCancel>Cancel</AlertDialogCancel>
168→            <AlertDialogAction onClick={handleAnalyze}>Re-analyze</AlertDialogAction>
169→          </AlertDialogFooter>
170→        </AlertDialogContent>
171→      </AlertDialog>
172→    </div>
173→  );
